// Metacircular Code Generator

const compiler_emit_zig = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) { emitted: struct { code: []const u8 } };
    pub fn handler(e: Input) Output {

    const MAX_SIZE = 64 * 1024; // 64KB buffer
    var buffer: [MAX_SIZE]u8 = undefined;
    var pos: usize = 0;
    
    // Helper function for writing strings
    const writeStr = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, str: []const u8) usize {
            if (p + str.len >= MAX_SIZE) return p;
            @memcpy(buf[p..p + str.len], str);
            return p + str.len;
        }
    }.call;
    
    // Helper function for equality comparison
    const eql = struct {
        fn call(a: []const u8, b: []const u8) bool {
            if (a.len != b.len) return false;
            for (a, 0..) |char, i| {
                if (char != b[i]) return false;
            }
            return true;
        }
    }.call;
    
    // Helper function to reindent text with additional spaces
    const reindentText = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, text: []const u8, additional_indent: []const u8) usize {
            var text_pos = p;
            var i: usize = 0;
            
            while (i < text.len) {
                // Find the end of the current line
                var line_end = i;
                while (line_end < text.len and text[line_end] != '\n') {
                    line_end += 1;
                }
                
                // Write additional indentation if the line is not empty
                if (line_end > i) {
                    // Check if line has content (not just whitespace)
                    var has_content = false;
                    var j = i;
                    while (j < line_end) : (j += 1) {
                        if (text[j] != ' ' and text[j] != '\t') {
                            has_content = true;
                            break;
                        }
                    }
                    
                    if (has_content) {
                        text_pos = writeStr(buf, text_pos, additional_indent);
                    }
                }
                
                // Write the line content
                if (line_end > i) {
                    @memcpy(buf[text_pos..text_pos + (line_end - i)], text[i..line_end]);
                    text_pos += line_end - i;
                }
                
                // Write the newline if present
                if (line_end < text.len) {
                    buf[text_pos] = '\n';
                    text_pos += 1;
                }
                
                i = line_end + 1;
            }
            
            return text_pos;
        }
    }.call;
    
    // Helper function to generate continuation body recursively
    const generateContinuationBody = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, cont: anytype, indent: []const u8, ast_items: anytype) usize {
            var inner_pos = p;
            
            // Process the pipeline steps
            if (cont.pipeline.len > 0) {
                for (cont.pipeline) |step| {
                    switch (step) {
                        .invocation => |inv| {
                            // Generate nested event invocation
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "const nested_result = ");
                            
                            // Check if event is in a module
                            var event_module: ?[]const u8 = null;
                            for (ast_items) |item| {
                                switch (item) {
                                    .module_decl => |module| {
                                        for (module.items) |mod_item| {
                                            switch (mod_item) {
                                                .event_decl => |event| {
                                                    if (event.path.len == inv.path.len) {
                                                        var matches = true;
                                                        for (event.path, 0..) |seg, j| {
                                                            if (!eql(seg, inv.path[j])) {
                                                                matches = false;
                                                                break;
                                                            }
                                                        }
                                                        if (matches) {
                                                            event_module = module.logical_name;
                                                            break;
                                                        }
                                                    }
                                                },
                                                else => {},
                                            }
                                        }
                                        if (event_module != null) break;
                                    },
                                    else => {},
                                }
                            }
                            
                            // Write event path
                            if (event_module) |mod| {
                                inner_pos = writeStr(buf, inner_pos, mod);
                                inner_pos = writeStr(buf, inner_pos, ".");
                                inner_pos = writeStr(buf, inner_pos, inv.path[inv.path.len - 1]);
                            } else {
                                for (inv.path, 0..) |segment, idx| {
                                    if (idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                    inner_pos = writeStr(buf, inner_pos, segment);
                                }
                            }
                            inner_pos = writeStr(buf, inner_pos, ".handler(.{");
                            
                            // Write arguments
                            for (inv.args, 0..) |arg, idx| {
                                if (idx > 0) inner_pos = writeStr(buf, inner_pos, ", ");
                                inner_pos = writeStr(buf, inner_pos, " .");
                                inner_pos = writeStr(buf, inner_pos, arg.name);
                                inner_pos = writeStr(buf, inner_pos, " = ");
                                inner_pos = writeStr(buf, inner_pos, arg.value);
                            }
                            inner_pos = writeStr(buf, inner_pos, " });\n");
                            
                            // Generate switch for nested continuations if any
                            if (cont.nested.len > 0) {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "switch (nested_result) {\n");
                                
                                // Generate nested continuations
                                for (cont.nested) |nested| {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    .");
                                    inner_pos = writeStr(buf, inner_pos, nested.branch);
                                    inner_pos = writeStr(buf, inner_pos, " => ");
                                    
                                    if (nested.binding) |binding| {
                                        inner_pos = writeStr(buf, inner_pos, "|");
                                        inner_pos = writeStr(buf, inner_pos, binding);
                                        inner_pos = writeStr(buf, inner_pos, "| {\n");
                                    } else {
                                        inner_pos = writeStr(buf, inner_pos, "{\n");
                                    }
                                    
                                    // Recursively generate nested body with increased indent
                                    var deeper_indent_buf: [64]u8 = undefined;
                                    var deeper_indent_len: usize = 0;
                                    @memcpy(deeper_indent_buf[0..indent.len], indent);
                                    deeper_indent_len = indent.len;
                                    const extra = "        ";
                                    @memcpy(deeper_indent_buf[deeper_indent_len..deeper_indent_len + extra.len], extra);
                                    deeper_indent_len += extra.len;
                                    const deeper_indent = deeper_indent_buf[0..deeper_indent_len];
                                    
                                    inner_pos = call(buf, inner_pos, nested, deeper_indent, ast_items);
                                    
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    },\n");
                                }
                                
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "}\n");
                            } else {
                                // No nested continuations, just consume the result
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = nested_result;\n");
                            }
                        },
                        .terminal => {
                            // Terminal step - suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "// Terminal\n");
                        },
                        else => {
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "// TODO: Handle other step types\n");
                        },
                    }
                }
            } else {
                // Empty pipeline
                inner_pos = writeStr(buf, inner_pos, indent);
                inner_pos = writeStr(buf, inner_pos, "// Empty continuation\n");
            }
            
            return inner_pos;
        }
    }.call;
    
    
    // Generate header
    pos = writeStr(&buffer, pos, "// Generated by Koru compiler.emit.zig event - METACIRCULAR!\n");
    pos = writeStr(&buffer, pos, "\n");
    
    // Check if there's a user-defined main function or any flows/events
    var has_user_main = false;
    var has_flows = false;
    var has_events = false;
    
    for (e.ast.items) |item| {
        switch (item) {
            .zig_line => |line| {
                // Simple check: if line starts with "pub fn main"
                if (line.content.len >= 11 and eql(line.content[0..11], "pub fn main")) {
                    has_user_main = true;
                }
            },
            .flow => {
                has_flows = true;
            },
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.len == 0 or !eql(event.path[0], "compiler")) {
                    has_events = true;
                }
            },
            else => {},
        }
    }
    
    // If user defined main and no Koru features, just output as-is
    if (has_user_main and !has_flows and !has_events) {
        // Just output zig_lines directly without module struct
        for (e.ast.items) |item| {
            switch (item) {
                .zig_line => |line| {
                    pos = writeStr(&buffer, pos, line.content);
                    pos = writeStr(&buffer, pos, "\n");
                },
                else => {},
            }
        }
        // Return early - no need for further processing
        const final_code = buffer[0..pos];
        return .{ .emitted = .{ .code = final_code } };
    }
    
    // First, generate imported module structs from ModuleDecl items
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => |module| {
                pos = writeStr(&buffer, pos, "pub const ");
                pos = writeStr(&buffer, pos, module.logical_name);
                pos = writeStr(&buffer, pos, " = struct {\n");
                
                // Process all items in the module
                for (module.items) |mod_item| {
                    switch (mod_item) {
                        .zig_line => |line| {
                            pos = writeStr(&buffer, pos, "    ");
                            pos = writeStr(&buffer, pos, line.content);
                            pos = writeStr(&buffer, pos, "\n");
                        },
                        .event_decl => |event| {
                            // Skip compiler events (they're only for compile-time use)
                            // TODO: Use event.is_compiler_internal flag once available
                            if (event.path.len > 0 and eql(event.path[0], "compiler")) {
                                continue;
                            }
                            
                            // Generate event struct
                            pos = writeStr(&buffer, pos, "    pub const ");
                            pos = writeStr(&buffer, pos, event.path[event.path.len - 1]);
                            pos = writeStr(&buffer, pos, " = struct {\n");
                            
                            // Input struct
                            pos = writeStr(&buffer, pos, "        pub const Input = struct {\n");
                            for (event.input.fields) |field| {
                                pos = writeStr(&buffer, pos, "            ");
                                pos = writeStr(&buffer, pos, field.name);
                                pos = writeStr(&buffer, pos, ": ");
                                if (field.is_file or field.is_embed_file) {
                                    pos = writeStr(&buffer, pos, "[]const u8");
                                } else {
                                    pos = writeStr(&buffer, pos, field.type);
                                }
                                pos = writeStr(&buffer, pos, ",\n");
                            }
                            pos = writeStr(&buffer, pos, "        };\n");
                            
                            // Output type - void for events with no branches
                            if (event.branches.len == 0) {
                                // Void event - no output
                                pos = writeStr(&buffer, pos, "        pub const Output = void;\n");
                            } else {
                                // Output union for events with branches
                                pos = writeStr(&buffer, pos, "        pub const Output = union(enum) {\n");
                                for (event.branches) |branch| {
                                    pos = writeStr(&buffer, pos, "            ");
                                    pos = writeStr(&buffer, pos, branch.name);
                                    pos = writeStr(&buffer, pos, ": struct {\n");
                                    for (branch.payload.fields) |field| {
                                        pos = writeStr(&buffer, pos, "                ");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ": ");
                                        pos = writeStr(&buffer, pos, field.type);
                                        pos = writeStr(&buffer, pos, ",\n");
                                    }
                                    pos = writeStr(&buffer, pos, "            },\n");
                                }
                                pos = writeStr(&buffer, pos, "        };\n");
                            }
                            
                            // Handler function
                            pos = writeStr(&buffer, pos, "        pub fn handler(e: Input) Output {\n");
                            
                            // Find implementation in the same module
                            var found_impl = false;
                            for (module.items) |impl_item| {
                                switch (impl_item) {
                                    .proc_decl => |proc| {
                                        if (proc.path.len == event.path.len) {
                                            var matches = true;
                                            for (proc.path, 0..) |seg, j| {
                                                if (!eql(seg, event.path[j])) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            if (matches) {
                                                pos = writeStr(&buffer, pos, "            _ = &e;\n");
                                                
                                                // Emit proc body with proper indentation
                                                pos = reindentText(&buffer, pos, proc.body, "        ");
                                                pos = writeStr(&buffer, pos, "\n");
                                                found_impl = true;
                                                break;
                                            }
                                        }
                                    },
                                    else => {},
                                }
                            }
                            
                            if (!found_impl) {
                                if (event.branches.len > 0) {
                                    pos = writeStr(&buffer, pos, "            return .{ .");
                                    pos = writeStr(&buffer, pos, event.branches[0].name);
                                    pos = writeStr(&buffer, pos, " = .{} };\n");
                                } else {
                                    pos = writeStr(&buffer, pos, "            return undefined;\n");
                                }
                            }
                            
                            pos = writeStr(&buffer, pos, "        }\n");
                            pos = writeStr(&buffer, pos, "    };\n");
                        },
                        else => {},
                    }
                }
                
                // Close the module struct
                pos = writeStr(&buffer, pos, "};\n\n");
            },
            else => {},
        }
    }
    
    // Now generate the main module struct
    pos = writeStr(&buffer, pos, "pub const main_module = struct {\n");
    
    // First pass: Collect zig_lines (imports) - inside the module struct!
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .zig_line => |line| {
                pos = writeStr(&buffer, pos, "    ");
                pos = writeStr(&buffer, pos, line.content);
                pos = writeStr(&buffer, pos, "\n");
            },
            else => {},
        }
    }
    
    // Second pass: Generate events (only local ones, not imported)
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.len > 0 and eql(event.path[0], "compiler")) {
                    continue;
                }
                
                // Write the event with proper indentation (we're inside main_module)
                pos = writeStr(&buffer, pos, "    pub const ");
                pos = writeStr(&buffer, pos, event.path[event.path.len - 1]);
                pos = writeStr(&buffer, pos, " = struct {\n");
                
                // Input struct
                pos = writeStr(&buffer, pos, "        pub const Input = struct {\n");
                for (event.input.fields) |field| {
                    pos = writeStr(&buffer, pos, "            ");
                    pos = writeStr(&buffer, pos, field.name);
                    pos = writeStr(&buffer, pos, ": ");
                    if (field.is_file or field.is_embed_file) {
                        pos = writeStr(&buffer, pos, "[]const u8");
                    } else {
                        pos = writeStr(&buffer, pos, field.type);
                    }
                    pos = writeStr(&buffer, pos, ",\n");
                }
                pos = writeStr(&buffer, pos, "        };\n");
                
                // Output type - void for events with no branches
                if (event.branches.len == 0) {
                    // Void event - no output
                    pos = writeStr(&buffer, pos, "        pub const Output = void;\n");
                } else {
                    // Output union for events with branches
                    pos = writeStr(&buffer, pos, "        pub const Output = union(enum) {\n");
                    for (event.branches) |branch| {
                        pos = writeStr(&buffer, pos, "            ");
                        pos = writeStr(&buffer, pos, branch.name);
                        pos = writeStr(&buffer, pos, ": struct {\n");
                        for (branch.payload.fields) |field| {
                            pos = writeStr(&buffer, pos, "                ");
                            pos = writeStr(&buffer, pos, field.name);
                            pos = writeStr(&buffer, pos, ": ");
                            pos = writeStr(&buffer, pos, field.type);
                            pos = writeStr(&buffer, pos, ",\n");
                        }
                        pos = writeStr(&buffer, pos, "            },\n");
                    }
                    pos = writeStr(&buffer, pos, "        };\n");
                }
                
                // Handler function
                pos = writeStr(&buffer, pos, "        pub fn handler(e: Input) Output {\n");
                
                // Find implementation
                var found_impl = false;
                for (e.ast.items) |impl_item| {
                    switch (impl_item) {
                        .proc_decl => |proc| {
                            if (proc.path.len == event.path.len) {
                                var matches = true;
                                for (proc.path, 0..) |seg, j| {
                                    if (!eql(seg, event.path[j])) {
                                        matches = false;
                                        break;
                                    }
                                }
                                if (matches) {
                                    // Generate implicit input bindings - destructure all input fields
                                    // This makes procs consistent with subflows by providing direct access to input fields
                                    for (event.input.fields) |field| {
                                        pos = writeStr(&buffer, pos, "            const ");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, " = e.");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ";\n");
                                    }
                                    // Suppress unused variable warnings for all destructured fields
                                    for (event.input.fields) |field| {
                                        pos = writeStr(&buffer, pos, "            _ = &");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ";\n");
                                    }
                                    
                                    // Keep _ = &e for backwards compatibility if proc uses e directly
                                    pos = writeStr(&buffer, pos, "            _ = &e;\n");
                                    
                                    // Emit proc body with proper indentation (add 8 more spaces to existing 4)
                                    pos = reindentText(&buffer, pos, proc.body, "        ");
                                    pos = writeStr(&buffer, pos, "\n");
                                    found_impl = true;
                                    break;
                                }
                            }
                        },
                        .subflow_impl => |subflow| {
                            if (subflow.event_path.len == event.path.len) {
                                var matches = true;
                                for (subflow.event_path, 0..) |seg, j| {
                                    if (!eql(seg, event.path[j])) {
                                        matches = false;
                                        break;
                                    }
                                }
                                if (matches) {
                                    switch (subflow.body) {
                                        .immediate => |bc| {
                                            // Suppress unused parameter warning
                                            pos = writeStr(&buffer, pos, "            _ = e;\n");
                                            pos = writeStr(&buffer, pos, "            return .{ .");
                                            pos = writeStr(&buffer, pos, bc.branch_name);
                                            pos = writeStr(&buffer, pos, " = .{");
                                            for (bc.fields, 0..) |field, k| {
                                                if (k > 0) pos = writeStr(&buffer, pos, ", ");
                                                pos = writeStr(&buffer, pos, " .");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, " = ");
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                            pos = writeStr(&buffer, pos, " } };\n");
                                        },
                                        .flow => |flow| {
                                            // Generate implicit input bindings for consistency with procs
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            const ");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, " = e.");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            // Suppress unused variable warnings
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            _ = &");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            pos = writeStr(&buffer, pos, "            _ = &e;\n");
                                            
                                            // Generate the invocation of the inner event
                                            pos = writeStr(&buffer, pos, "            const result = ");
                                            
                                            // Write event path (e.g., "transform")
                                            for (flow.invocation.path, 0..) |segment, idx| {
                                                if (idx > 0) pos = writeStr(&buffer, pos, ".");
                                                pos = writeStr(&buffer, pos, segment);
                                            }
                                            pos = writeStr(&buffer, pos, ".handler(.{");
                                            
                                            // Write arguments, mapping from input parameters
                                            for (flow.invocation.args, 0..) |arg, idx| {
                                                if (idx > 0) pos = writeStr(&buffer, pos, ", ");
                                                pos = writeStr(&buffer, pos, " .");
                                                pos = writeStr(&buffer, pos, arg.name);
                                                pos = writeStr(&buffer, pos, " = e.");
                                                // Map the arg value to the input field
                                                // arg.value should be the input field name
                                                pos = writeStr(&buffer, pos, arg.value);
                                            }
                                            pos = writeStr(&buffer, pos, " });\n");
                                            
                                            // Generate switch statement to map branches
                                            pos = writeStr(&buffer, pos, "            switch (result) {\n");
                                            
                                            // Generate each continuation as a case
                                            for (flow.continuations) |cont| {
                                                pos = writeStr(&buffer, pos, "                .");
                                                pos = writeStr(&buffer, pos, cont.branch);
                                                pos = writeStr(&buffer, pos, " => ");
                                                
                                                // Check if there's a binding
                                                if (cont.binding) |binding| {
                                                    pos = writeStr(&buffer, pos, "|");
                                                    pos = writeStr(&buffer, pos, binding);
                                                    pos = writeStr(&buffer, pos, "| {\n");
                                                } else {
                                                    pos = writeStr(&buffer, pos, "{\n");
                                                }
                                                
                                                // Generate the return statement with branch constructor
                                                // For now, assume single step in pipeline is branch constructor
                                                if (cont.pipeline.len > 0) {
                                                    switch (cont.pipeline[0]) {
                                                        .branch_constructor => |bc| {
                                                            pos = writeStr(&buffer, pos, "                    return .{ .");
                                                            pos = writeStr(&buffer, pos, bc.branch_name);
                                                            pos = writeStr(&buffer, pos, " = .{");
                                                            
                                                            // Generate fields
                                                            for (bc.fields, 0..) |field, k| {
                                                                if (k > 0) pos = writeStr(&buffer, pos, ", ");
                                                                pos = writeStr(&buffer, pos, " .");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, " = ");
                                                                
                                                                // The field.type contains the expression to evaluate
                                                                // Check if it references the binding or parent input
                                                                // Simple heuristic: if it starts with binding name, use as-is
                                                                // Otherwise, it might be a parent input field, prefix with "e."
                                                                var needs_e_prefix = true;
                                                                if (cont.binding) |binding| {
                                                                    // Check if field.type starts with binding name
                                                                    if (field.type.len >= binding.len) {
                                                                        var field_matches = true;
                                                                        for (binding, 0..) |ch, idx| {
                                                                            if (field.type[idx] != ch) {
                                                                                field_matches = false;
                                                                                break;
                                                                            }
                                                                        }
                                                                        // Also check that it's followed by . or end
                                                                        if (field_matches and (field.type.len == binding.len or field.type[binding.len] == '.')) {
                                                                            needs_e_prefix = false;
                                                                        }
                                                                    }
                                                                }
                                                                
                                                                // Check for literal values (numbers, strings)
                                                                if (field.type.len > 0) {
                                                                    const first_char = field.type[0];
                                                                    if (first_char == '"' or (first_char >= '0' and first_char <= '9') or first_char == '-') {
                                                                        needs_e_prefix = false;
                                                                    }
                                                                }
                                                                
                                                                if (needs_e_prefix) {
                                                                    pos = writeStr(&buffer, pos, "e.");
                                                                }
                                                                pos = writeStr(&buffer, pos, field.type);
                                                            }
                                                            pos = writeStr(&buffer, pos, " } };\n");
                                                        },
                                                        else => {
                                                            // Fallback for non-branch-constructor steps
                                                            pos = writeStr(&buffer, pos, "                    return undefined; // TODO: handle other step types\n");
                                                        },
                                                    }
                                                } else {
                                                    // No pipeline steps - shouldn't happen but handle gracefully
                                                    pos = writeStr(&buffer, pos, "                    return undefined; // Empty pipeline\n");
                                                }
                                                
                                                pos = writeStr(&buffer, pos, "                },\n");
                                            }
                                            
                                            pos = writeStr(&buffer, pos, "            }\n");
                                        },
                                    }
                                    found_impl = true;
                                    break;
                                }
                            }
                        },
                        else => {},
                    }
                }
                
                if (!found_impl) {
                    // Add unused parameter suppression
                    pos = writeStr(&buffer, pos, "            _ = e;\n");
                    
                    if (event.branches.len > 0) {
                        // Return with proper field values
                        pos = writeStr(&buffer, pos, "            return .{ .");
                        pos = writeStr(&buffer, pos, event.branches[0].name);
                        pos = writeStr(&buffer, pos, " = .{");
                        
                        // Generate default values for each field in the branch
                        for (event.branches[0].payload.fields) |field| {
                            pos = writeStr(&buffer, pos, " .");
                            pos = writeStr(&buffer, pos, field.name);
                            pos = writeStr(&buffer, pos, " = ");
                            
                            // Generate appropriate default based on type
                            if (eql(field.type, "i32")) {
                                pos = writeStr(&buffer, pos, "0");
                            } else if (eql(field.type, "[]const u8")) {
                                pos = writeStr(&buffer, pos, "\"\"");
                            } else if (eql(field.type, "bool")) {
                                pos = writeStr(&buffer, pos, "false");
                            } else {
                                pos = writeStr(&buffer, pos, "undefined");
                            }
                            pos = writeStr(&buffer, pos, ",");
                        }
                        
                        pos = writeStr(&buffer, pos, "} };\n");
                    } else {
                        pos = writeStr(&buffer, pos, "            return undefined;\n");
                    }
                }
                
                pos = writeStr(&buffer, pos, "        }\n");
                
                // Close the event struct
                pos = writeStr(&buffer, pos, "    };\n");
            },
            else => {},
        }
    }
    
    // Generate simple tap registry (placeholder for now) - inside main_module
    pos = writeStr(&buffer, pos, "\n    // Event Tap Registry (placeholder)\n");
    pos = writeStr(&buffer, pos, "    const TapRegistry = struct {\n");
    pos = writeStr(&buffer, pos, "        pub fn invokeInputTaps(event_name: []const u8, input: anytype) void {\n");
    pos = writeStr(&buffer, pos, "            // TODO: Implement tap lookup and invocation\n");
    pos = writeStr(&buffer, pos, "            _ = event_name;\n");
    pos = writeStr(&buffer, pos, "            _ = input;\n");
    pos = writeStr(&buffer, pos, "        }\n");
    pos = writeStr(&buffer, pos, "        pub fn invokeOutputTaps(event_name: []const u8, output: anytype) void {\n");
    pos = writeStr(&buffer, pos, "            // TODO: Implement tap lookup and invocation\n");
    pos = writeStr(&buffer, pos, "            _ = event_name;\n");
    pos = writeStr(&buffer, pos, "            _ = output;\n");
    pos = writeStr(&buffer, pos, "        }\n");
    pos = writeStr(&buffer, pos, "    };\n");
    
    // Continue with flows as functions (we're already inside main_module)
    
    var flow_counter: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .flow => |flow| {
                pos = writeStr(&buffer, pos, "    pub fn flow");
                // Simple number writing
                if (flow_counter == 0) {
                    pos = writeStr(&buffer, pos, "0");
                } else if (flow_counter == 1) {
                    pos = writeStr(&buffer, pos, "1");
                } else if (flow_counter == 2) {
                    pos = writeStr(&buffer, pos, "2");
                } else if (flow_counter == 3) {
                    pos = writeStr(&buffer, pos, "3");
                } else if (flow_counter == 4) {
                    pos = writeStr(&buffer, pos, "4");
                } else {
                    pos = writeStr(&buffer, pos, "N");
                }
                pos = writeStr(&buffer, pos, "() void {\n");
                
                // Generate the flow body
                // TODO: Add input tap injection here when tap registry is ready
                // For now, we just generate a comment placeholder
                pos = writeStr(&buffer, pos, "        // [TAP INJECTION POINT: INPUT]\n");
                pos = writeStr(&buffer, pos, "        const result = ");
                
                // Check if this event is in a module or main
                var event_module: ?[]const u8 = null;
                
                // First check modules
                for (e.ast.items) |evt_item| {
                    switch (evt_item) {
                        .module_decl => |module| {
                            for (module.items) |mod_item| {
                                switch (mod_item) {
                                    .event_decl => |event| {
                                        if (event.path.len == flow.invocation.path.len) {
                                            var matches = true;
                                            for (event.path, 0..) |seg, j| {
                                                if (!eql(seg, flow.invocation.path[j])) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            if (matches) {
                                                event_module = module.logical_name;
                                                break;
                                            }
                                        }
                                    },
                                    else => {},
                                }
                            }
                            if (event_module != null) break;
                        },
                        else => {},
                    }
                }
                
                // Use module prefix if imported, otherwise local
                if (event_module) |mod| {
                    pos = writeStr(&buffer, pos, mod);
                    pos = writeStr(&buffer, pos, ".");
                    pos = writeStr(&buffer, pos, flow.invocation.path[flow.invocation.path.len - 1]);
                } else {
                    pos = writeStr(&buffer, pos, flow.invocation.path[flow.invocation.path.len - 1]);
                }
                pos = writeStr(&buffer, pos, ".handler(.{");
                
                for (flow.invocation.args, 0..) |arg, i| {
                    if (i > 0) pos = writeStr(&buffer, pos, ", ");
                    pos = writeStr(&buffer, pos, " .");
                    pos = writeStr(&buffer, pos, arg.name);
                    pos = writeStr(&buffer, pos, " = ");
                    pos = writeStr(&buffer, pos, arg.value);
                }
                pos = writeStr(&buffer, pos, " });\n");
                
                // TODO: Add output tap injection here when tap registry is ready
                pos = writeStr(&buffer, pos, "        // [TAP INJECTION POINT: OUTPUT]\n");
                
                // Generate continuation handling
                pos = writeStr(&buffer, pos, "        switch (result) {\n");
                
                // Group continuations by branch name
                var i: usize = 0;
                while (i < flow.continuations.len) {
                    const branch_name = flow.continuations[i].branch;
                    
                    // Count how many continuations have this branch name
                    var same_branch_count: usize = 1;
                    while (i + same_branch_count < flow.continuations.len) {
                        if (!eql(flow.continuations[i + same_branch_count].branch, branch_name)) break;
                        same_branch_count += 1;
                    }
                    
                    pos = writeStr(&buffer, pos, "            .");
                    pos = writeStr(&buffer, pos, branch_name);
                    pos = writeStr(&buffer, pos, " => ");
                    
                    // Get binding from first continuation with this branch
                    if (flow.continuations[i].binding) |binding| {
                        pos = writeStr(&buffer, pos, "|");
                        pos = writeStr(&buffer, pos, binding);
                        pos = writeStr(&buffer, pos, "| {\n");
                    } else {
                        pos = writeStr(&buffer, pos, "{\n");
                    }
                    
                    // If there are multiple continuations with same branch, generate if-else chain
                    if (same_branch_count > 1) {
                        var j: usize = 0;
                        while (j < same_branch_count) {
                            const cont = flow.continuations[i + j];
                            
                            if (cont.condition) |cond| {
                                if (j == 0) {
                                    pos = writeStr(&buffer, pos, "                if (");
                                } else {
                                    pos = writeStr(&buffer, pos, "                } else if (");
                                }
                                
                                // Generate condition expression
                                // Simple replacement of binding references
                                var cond_pos: usize = 0;
                                while (cond_pos < cond.len) {
                                    // Check if we're at the start of the binding name
                                    if (cont.binding) |binding| {
                                        if (cond_pos + binding.len <= cond.len) {
                                            var matches = true;
                                            for (binding, 0..) |ch, idx| {
                                                if (cond[cond_pos + idx] != ch) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            
                                            // Check it's a word boundary
                                            if (matches) {
                                                const after = if (cond_pos + binding.len < cond.len) cond[cond_pos + binding.len] else 0;
                                                const before = if (cond_pos > 0) cond[cond_pos - 1] else 0;
                                                const is_word_boundary = (before < 'a' or before > 'z') and 
                                                                        (before < 'A' or before > 'Z') and
                                                                        (before < '0' or before > '9') and
                                                                        before != '_' and
                                                                        (after < 'a' or after > 'z') and
                                                                        (after < 'A' or after > 'Z') and
                                                                        (after < '0' or after > '9') and
                                                                        after != '_';
                                                
                                                if (is_word_boundary) {
                                                    // Write the binding variable
                                                    pos = writeStr(&buffer, pos, binding);
                                                    cond_pos += binding.len;
                                                    continue;
                                                }
                                            }
                                        }
                                    }
                                    
                                    // Copy the character as-is
                                    var char_buf: [1]u8 = .{cond[cond_pos]};
                                    pos = writeStr(&buffer, pos, &char_buf);
                                    cond_pos += 1;
                                }
                                
                                pos = writeStr(&buffer, pos, ") {\n");
                                
                                // Generate the continuation body with extra indent
                                pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items);
                            } else {
                                // No condition - this is the default/else case
                                if (j > 0) {
                                    pos = writeStr(&buffer, pos, "                } else {\n");
                                    pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items);
                                } else {
                                    // Single continuation without condition
                                    pos = generateContinuationBody(&buffer, pos, cont, "                ", e.ast.items);
                                }
                            }
                            j += 1;
                        }
                        
                        // Close the if-else chain if we had conditions
                        if (flow.continuations[i].condition != null) {
                            pos = writeStr(&buffer, pos, "                }\n");
                        }
                    } else {
                        // Single continuation for this branch
                        const cont = flow.continuations[i];
                        if (cont.condition) |cond| {
                            // Generate if statement for single where clause
                            pos = writeStr(&buffer, pos, "                if (");
                            
                            // Write condition (with simple binding replacement)
                            var cond_pos: usize = 0;
                            while (cond_pos < cond.len) {
                                var char_buf: [1]u8 = .{cond[cond_pos]};
                                pos = writeStr(&buffer, pos, &char_buf);
                                cond_pos += 1;
                            }
                            
                            pos = writeStr(&buffer, pos, ") {\n");
                            pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items);
                            pos = writeStr(&buffer, pos, "                }\n");
                        } else {
                            // No condition
                            pos = generateContinuationBody(&buffer, pos, cont, "                ", e.ast.items);
                        }
                    }
                    
                    pos = writeStr(&buffer, pos, "            },\n");
                    
                    // Move to next set of branches
                    i += same_branch_count;
                }
                
                pos = writeStr(&buffer, pos, "        }\n");
                pos = writeStr(&buffer, pos, "    }\n\n");
                
                flow_counter += 1;
            },
            else => {},
        }
    }
    
    // Close the main_module struct
    pos = writeStr(&buffer, pos, "};\n\n");
    
    // Generate minimal main function that calls flows from main_module
    pos = writeStr(&buffer, pos, "pub fn main() void {\n");
    
    var flow_count: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .flow => {
                pos = writeStr(&buffer, pos, "    main_module.flow");
                if (flow_count == 0) {
                    pos = writeStr(&buffer, pos, "0");
                } else if (flow_count == 1) {
                    pos = writeStr(&buffer, pos, "1");
                } else if (flow_count == 2) {
                    pos = writeStr(&buffer, pos, "2");
                } else if (flow_count == 3) {
                    pos = writeStr(&buffer, pos, "3");
                } else if (flow_count == 4) {
                    pos = writeStr(&buffer, pos, "4");
                } else {
                    pos = writeStr(&buffer, pos, "N");
                }
                pos = writeStr(&buffer, pos, "();\n");
                flow_count += 1;
            },
            else => {},
        }
    }
    
    pos = writeStr(&buffer, pos, "}\n");
    
    // Return the emitted code!
    const final_code = buffer[0..pos];
    return .{ .emitted = .{ .code = final_code } };
    }
};

// Bootstrap coordinator - now calls the REAL compiler.emit.zig!
const compiler_coordinate_default = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) {
        coordinated: struct {
            ast: *const SourceFile,
            code: []const u8, 
            metrics: []const u8,
        },
    };
    
    pub fn handler(e: Input) Output {
        // Call the REAL compiler.emit.zig that was generated above!
        const emit_result = compiler_emit_zig.handler(.{ .ast = e.ast });
        
        return .{ .coordinated = .{
            .ast = e.ast,
            .code = emit_result.emitted.code,
            .metrics = "Metacircular compilation complete!",
        }};
    }
};
// Compile-time code generation
const ComptimeEmitter = struct {
    pub fn emit(ast: *const SourceFile) [64*1024]u8 {
        @setEvalBranchQuota(100000);  // Increase branch quota for complex ASTs
        const result = compiler_coordinate_default.handler(.{ .ast = ast });
        var buf: [64*1024]u8 = [_]u8{0} ** (64*1024);
        const copy_len = @min(result.coordinated.code.len, 64*1024);
        @memcpy(buf[0..copy_len], result.coordinated.code[0..copy_len]);
        return buf;
    }
};

// Generate code at compile-time from the AST
const generated_code_buffer = ComptimeEmitter.emit(&PROGRAM_AST);
// For now, just use the full buffer - we'll trim zeros at runtime
const generated_code = generated_code_buffer[0..];

// Standard library import for the backend
const std = @import("std");
// === KORU BACKEND CODE GENERATOR ===
// This outputs the final Zig code generated by compiler.emit.zig

pub fn main() !void {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    const allocator = gpa.allocator();
    defer _ = gpa.deinit();
    
    // Get the output filename from argv (passed from koruc)
    const args = try std.process.argsAlloc(allocator);
    defer std.process.argsFree(allocator, args);
    
    // Default output names
    const emitted_file = "output_emitted.zig";
    const output_exe = if (args.len > 1) args[1] else "a.out";
    
    // Find actual length (trim trailing zeros)
    var actual_len: usize = generated_code.len;
    while (actual_len > 0 and generated_code[actual_len - 1] == 0) {
        actual_len -= 1;
    }
    const trimmed_code = generated_code[0..actual_len];
    
    // Write the generated code to a file
    const file = try std.fs.cwd().createFile(emitted_file, .{});
    defer file.close();
    try file.writeAll(trimmed_code);
    
    // Report what we generated
    const stdout = std.fs.File.stdout();
    var buf: [512]u8 = undefined;
    const msg = try std.fmt.bufPrint(&buf, "✓ Generated {s} ({d} bytes)\n", .{emitted_file, actual_len});
    try stdout.writeAll(msg);
    
    // Now compile the emitted code  
    var emit_path_buf: [256]u8 = undefined;
    const emit_path = try std.fmt.bufPrint(&emit_path_buf, "-femit-bin={s}", .{output_exe});
    const argv = [_][]const u8{ "zig", "build-exe", emitted_file, emit_path };
    const result = std.process.Child.run(.{
        .allocator = allocator,
        .argv = &argv,
    }) catch |err| {
        const stderr = std.fs.File.stderr();
        var err_buf: [512]u8 = undefined;
        const err_msg = try std.fmt.bufPrint(&err_buf, "✗ Failed to spawn zig compiler: {}\n", .{err});
        try stderr.writeAll(err_msg);
        std.process.exit(1);
    };
    defer allocator.free(result.stdout);
    defer allocator.free(result.stderr);
    
    const stdout2 = std.fs.File.stdout();
    var buf2: [512]u8 = undefined;
    if (result.term.Exited == 0) {
        const msg2 = try std.fmt.bufPrint(&buf2, "✓ Compiled to {s}\n", .{output_exe});
        try stdout2.writeAll(msg2);
    } else {
        const msg2 = try std.fmt.bufPrint(&buf2, "✗ Compilation failed\n", .{});
        try stdout2.writeAll(msg2);
        if (result.stderr.len > 0) {
            var err_buf2: [1024]u8 = undefined;
            const err_msg2 = try std.fmt.bufPrint(&err_buf2, "Error: {s}\n", .{result.stderr});
            try std.fs.File.stderr().writeAll(err_msg2);
        }
        std.process.exit(1);
    }
}